declare namespace NodeJS {
  interface ProcessEnv {
    /**
     * The built directory structure
     *
     * ```tree
     * ├─┬─┬ dist
     * │ │ └── index.html
     * │ │
     * │ ├─┬ dist-electron
     * │ │ ├── main.js
     * │ │ └── preload.js
     * │
     * ```
     */
    APP_ROOT: string
    /** /dist/ or /public/ */
    VITE_PUBLIC: string
    /** Local AdonisJS origin used by the Electron shell during development. */
    APP_URL?: string
    /** Override for the renderer URL loaded by the Electron window. */
    APP_SERVER_URL?: string
  }
}
